const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_PREMIUM;

const sumBasePremiums = (items: any[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const components = items.filter(isComponent);

  const mainTotal = mainItems.reduce(
    (sum, item) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0),
    0,
  );

  const componentCounts: Record<string, number> = {};
  for (const item of components) {
    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
  }

  const componentTotal = Object.values(componentCounts).reduce(
    (sum, count) => sum + componentGroupPremium(count),
    0,
  );

  return mainTotal + componentTotal;
};

